'use client'
import { cn } from '@cascivo/core'
import type { HTMLAttributes, ReactNode } from 'react'
import styles from './input-group.module.css'

export interface InputGroupAddonProps extends HTMLAttributes<HTMLSpanElement> {
  /** Visual side, logical: 'inline-start' (leading) or 'inline-end' (trailing). */
  align?: 'inline-start' | 'inline-end'
  children: ReactNode
}

/** Inline adornment (icon, unit) rendered INSIDE the field border. Decorative by default. */
export function InputGroupAddon({
  align = 'inline-start',
  children,
  className,
  ...props
}: InputGroupAddonProps) {
  return (
    <span
      className={cn(styles['inline-addon'], className)}
      data-align={align}
      aria-hidden="true"
      {...props}
    >
      {children}
    </span>
  )
}

export interface InputGroupProps extends Omit<HTMLAttributes<HTMLDivElement>, 'prefix' | 'suffix'> {
  prefix?: ReactNode
  suffix?: ReactNode
  children: ReactNode
}

export function InputGroup({ prefix, suffix, children, className, ...props }: InputGroupProps) {
  return (
    <div
      className={cn(styles['input-group'], className)}
      data-has-prefix={prefix ? '' : undefined}
      data-has-suffix={suffix ? '' : undefined}
      {...props}
    >
      {prefix && (
        <span className={styles['addon']} data-position="prefix">
          {prefix}
        </span>
      )}
      <span className={styles['input-wrap']}>{children}</span>
      {suffix && (
        <span className={styles['addon']} data-position="suffix">
          {suffix}
        </span>
      )}
    </div>
  )
}

export interface ButtonGroupProps extends HTMLAttributes<HTMLDivElement> {
  children: ReactNode
}

export function ButtonGroup({ children, className, ...props }: ButtonGroupProps) {
  return (
    <div className={cn(styles['button-group'], className)} role="group" {...props}>
      {children}
    </div>
  )
}

@layer cascivo.component {
  .input-group {
    display: flex;
    align-items: stretch;
    width: 100%;

    /* Remove adjacent border radii for connected look */
    &[data-has-prefix] .input-wrap > * {
      border-start-start-radius: 0;
      border-end-start-radius: 0;
    }

    &[data-has-suffix] .input-wrap > * {
      border-start-end-radius: 0;
      border-end-end-radius: 0;
    }

    &[data-has-prefix] .addon[data-position='prefix'] {
      border-start-end-radius: 0;
      border-end-end-radius: 0;
      border-inline-end: none;
    }

    &[data-has-suffix] .addon[data-position='suffix'] {
      border-start-start-radius: 0;
      border-end-start-radius: 0;
      border-inline-start: none;
    }
  }

  .input-wrap {
    flex: 1;
    min-width: 0;

    & > * {
      width: 100%;
    }
  }

  .addon {
    display: inline-flex;
    align-items: center;
    padding-inline: var(--cascivo-space-3);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-subtle);
    background-color: var(--cascivo-color-bg-subtle);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-field);
    white-space: nowrap;
    flex-shrink: 0;
  }

  /* ── Inline addons: group renders the border, input goes naked ── */
  .input-group:has(.inline-addon) {
    display: flex;
    align-items: center;
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-field, var(--cascivo-radius-control));
    background: var(--cascivo-color-bg);
    transition:
      border-color 120ms ease,
      box-shadow 120ms ease;
  }

  .input-group:has(.inline-addon):focus-within {
    border-color: var(--cascivo-color-accent);
    box-shadow: var(--cascivo-focus-ring);
  }

  /* strip the inner input chrome — the group owns it now */
  .input-group:has(.inline-addon) .input-wrap input {
    border: none;
    box-shadow: none;
    background: transparent;
    outline: none;
  }

  .inline-addon {
    display: inline-flex;
    align-items: center;
    color: var(--cascivo-color-text-subtle);
    pointer-events: none;
  }

  .inline-addon[data-align='inline-start'] {
    order: -1;
    padding-inline-start: var(--cascivo-space-3);
  }

  .inline-addon[data-align='inline-end'] {
    order: 1;
    padding-inline-end: var(--cascivo-space-3);
  }

  .inline-addon svg {
    inline-size: 1rem;
    block-size: 1rem;
  }

  .button-group {
    display: inline-flex;
    align-items: stretch;

    /* Collapse internal borders between buttons */
    & > *:not(:first-child) {
      border-start-start-radius: 0;
      border-end-start-radius: 0;
      margin-inline-start: -1px;
    }

    & > *:not(:last-child) {
      border-start-end-radius: 0;
      border-end-end-radius: 0;
    }

    & > *:focus-visible {
      position: relative;
      z-index: 1;
    }
  }
}
